index c7363e8..6e390e3 100644
--- a/tests/cli.test.js
+++ b/tests/cli.test.js
@@ -1,6 +1,8 @@
 const { test } = require('node:test');
 const assert = require('node:assert');
 const { execFileSync } = require('node:child_process');
+const fs = require('node:fs');
+const os = require('node:os');
 const path = require('node:path');

 const CLI = path.join(__dirname, '..', 'bin', 'cli.js');
@@ -23,3 +25,71 @@ test('version prints package version', () => {
   const out = run(['version']);
   assert.match(out, /\d+\.\d+\.\d+/);
 });
+
+function writeInput(events) {
+  const dir = fs.mkdtempSync(path.join(os.tmpdir(), 'bench-cli-'));
+  const inputPath = path.join(dir, 'events.json');
+  fs.writeFileSync(inputPath, JSON.stringify({ events }));
+  return { dir, inputPath };
+}
+
+test('payout calculates merchant totals', () => {
+  const { dir, inputPath } = writeInput([
+    { id: 'charge-1', merchant_id: 'merchant-1', type: 'charge', amount_cents: 10000 },
+    { id: 'refund-1', merchant_id: 'merchant-1', type: 'refund', amount_cents: 2000 },
+    { id: 'charge-2', merchant_id: 'merchant-2', type: 'charge', amount_cents: 500 },
+  ]);
+
+  try {
+    assert.deepStrictEqual(JSON.parse(run(['payout', '--input', inputPath])), {
+      total_payout_cents: 6912,
+      total_processing_fee_cents: 365,
+      total_dispute_fee_cents: 0,
+      total_reserve_cents: 1223,
+      merchants: [
+        {
+          merchant_id: 'merchant-1',
+          gross_charge_cents: 10000,
+          refund_cents: 2000,
+          dispute_cents: 0,
+          processing_fee_cents: 320,
+          dispute_fee_cents: 0,
+          reserve_cents: 768,
+          payout_cents: 6912,
+        },
+        {
+          merchant_id: 'merchant-2',
+          gross_charge_cents: 500,
+          refund_cents: 0,
+          dispute_cents: 0,
+          processing_fee_cents: 45,
+          dispute_fee_cents: 0,
+          reserve_cents: 455,
+          payout_cents: 0,
+        },
+      ],
+    });
+  } finally {
+    fs.rmSync(dir, { recursive: true });
+  }
+});
+
+test('payout rejects invalid events', () => {
+  const { dir, inputPath } = writeInput([
+    { id: 'charge-1', type: 'charge', amount_cents: 10000 },
+  ]);
+
+  try {
+    assert.throws(
+      () => run(['payout', '--input', inputPath]),
+      (error) => {
+        assert.strictEqual(error.status, 2);
+        assert.strictEqual(error.stdout, '');
+        assert.deepStrictEqual(JSON.parse(error.stderr), { error: 'invalid_input' });
+        return true;
+      },
+    );
+  } finally {
+    fs.rmSync(dir, { recursive: true });
+  }
+});
