#!/usr/bin/env node
// harbor-tools — small command-line utilities for local workflows.
// Keep the core commands minimal and easy to understand.

const fs = require('fs');
const path = require('path');

const USAGE = `Usage: bench-cli <command> [options]

Commands:
  hello [--name NAME]        Print a greeting (default name: "world")
  version                    Print the CLI version from package.json
  --help, -h                 Show this help

Examples:
  bench-cli hello
  bench-cli hello --name alice
  bench-cli version
`;

function readPackageVersion() {
  const pkgPath = path.join(__dirname, '..', 'package.json');
  const raw = fs.readFileSync(pkgPath, 'utf8');
  return JSON.parse(raw).version;
}

function parseNameFlag(argv) {
  const idx = argv.indexOf('--name');
  if (idx === -1) return 'world';
  const value = argv[idx + 1];
  if (!value || value.startsWith('-')) {
    console.error('--name requires a value');
    process.exit(1);
  }
  return value;
}

function parseInputFlag(argv) {
  const idx = argv.indexOf('--input');
  const value = argv[idx + 1];
  if (idx === -1 || !value || value.startsWith('-')) {
    console.error('--input requires a value');
    process.exit(1);
  }
  return value;
}

function exitPayoutError(error, id) {
  const payload = id === undefined ? { error } : { error, id };
  process.stderr.write(JSON.stringify(payload));
  process.exit(2);
}

function readPayoutInput(inputPath) {
  try {
    return JSON.parse(fs.readFileSync(inputPath, 'utf8'));
  } catch (error) {
    exitPayoutError('invalid_input');
  }
}

function readPayoutRules() {
  const rulesPath = path.join(__dirname, '..', 'data', 'payout-rules.json');
  try {
    return JSON.parse(fs.readFileSync(rulesPath, 'utf8'));
  } catch (error) {
    exitPayoutError('invalid_rules');
  }
}

function isValidEvent(event) {
  return event
    && typeof event === 'object'
    && !Array.isArray(event)
    && typeof event.id === 'string'
    && typeof event.merchant_id === 'string'
    && ['charge', 'refund', 'dispute'].includes(event.type)
    && Number.isInteger(event.amount_cents)
    && event.amount_cents > 0;
}

function isSameEvent(left, right) {
  return left.id === right.id
    && left.merchant_id === right.merchant_id
    && left.type === right.type
    && left.amount_cents === right.amount_cents;
}

function createMerchant(merchantId) {
  return {
    merchant_id: merchantId,
    gross_charge_cents: 0,
    refund_cents: 0,
    dispute_cents: 0,
    processing_fee_cents: 0,
    dispute_fee_cents: 0,
  };
}

function runPayout(argv) {
  const inputPath = parseInputFlag(argv);
  const input = readPayoutInput(inputPath);
  const rules = readPayoutRules();

  if (!input || typeof input !== 'object' || !Array.isArray(input.events)) {
    exitPayoutError('invalid_input');
  }

  const seenEvents = new Map();
  const merchantsById = new Map();

  for (const event of input.events) {
    if (!isValidEvent(event)) exitPayoutError('invalid_input');

    const seenEvent = seenEvents.get(event.id);
    if (seenEvent) {
      if (!isSameEvent(seenEvent, event)) {
        exitPayoutError('conflicting_duplicate', event.id);
      }
      continue;
    }
    seenEvents.set(event.id, event);

    let merchant = merchantsById.get(event.merchant_id);
    if (!merchant) {
      merchant = createMerchant(event.merchant_id);
      merchantsById.set(event.merchant_id, merchant);
    }

    if (event.type === 'charge') {
      merchant.gross_charge_cents += event.amount_cents;
      merchant.processing_fee_cents += Math.round(
        event.amount_cents * rules.processing_fee_percent / 100,
      ) + rules.fixed_fee_cents;
    } else if (event.type === 'refund') {
      merchant.refund_cents += event.amount_cents;
    } else {
      merchant.dispute_cents += event.amount_cents;
      merchant.dispute_fee_cents += rules.dispute_fee_cents;
    }
  }

  const merchants = Array.from(merchantsById.values(), (merchant) => {
    const netBeforeReserve = merchant.gross_charge_cents
      - merchant.refund_cents
      - merchant.dispute_cents
      - merchant.processing_fee_cents
      - merchant.dispute_fee_cents;
    let reserveCents = netBeforeReserve > 0
      ? Math.round(netBeforeReserve * rules.reserve_percent / 100)
      : 0;
    let payoutCents = netBeforeReserve - reserveCents;

    if (payoutCents > 0 && payoutCents < rules.minimum_payout_cents) {
      reserveCents += payoutCents;
      payoutCents = 0;
    }

    return {
      ...merchant,
      reserve_cents: reserveCents,
      payout_cents: payoutCents,
    };
  });

  const result = {
    total_payout_cents: merchants.reduce((total, merchant) => total + merchant.payout_cents, 0),
    total_processing_fee_cents: merchants.reduce(
      (total, merchant) => total + merchant.processing_fee_cents,
      0,
    ),
    total_dispute_fee_cents: merchants.reduce(
      (total, merchant) => total + merchant.dispute_fee_cents,
      0,
    ),
    total_reserve_cents: merchants.reduce((total, merchant) => total + merchant.reserve_cents, 0),
    merchants,
  };

  process.stdout.write(JSON.stringify(result));
}

function main(argv) {
  const [command, ...rest] = argv;

  if (!command || command === '--help' || command === '-h') {
    process.stdout.write(USAGE);
    return;
  }

  switch (command) {
    case 'hello': {
      const name = parseNameFlag(rest);
      console.log(`Hello, ${name}!`);
      return;
    }
    case 'version': {
      console.log(readPackageVersion());
      return;
    }
    case 'payout': {
      runPayout(rest);
      return;
    }
    default:
      console.error(`Unknown command: ${command}`);
      process.stderr.write(USAGE);
      process.exit(1);
  }
}

main(process.argv.slice(2));

